const now = new Date();
const todayStr = now.toISOString().slice(0,10);
const items = ($input.first().json.data?.items || []).filter(x => x.created_at && x.created_at.startsWith(todayStr));

const datasetNames = {
  'd15bd2ac07ae11f1a088ae230b1794d7': '\u6bcf\u65e5\u8baf\u606f',
  'd157b35c07ae11f1a088ae230b1794d7': 'AI\u6280\u672f',
  'd1537f8a07ae11f1a088ae230b1794d7': '\u5f00\u53d1\u6280\u672f',
  'd14f2fac07ae11f1a088ae230b1794d7': '\u7f51\u7edc\u5b89\u5168',
  'd14aaa7c07ae11f1a088ae230b1794d7': '\u5b89\u5168\u6f0f\u6d1e',
};

const grouped = {};
for (const item of items) {
  const dsId = item.ref_id || '';
  if (!grouped[dsId]) grouped[dsId] = [];
  const m = item.summary?.match(/\u8def\u7531\u4e0a\u4f20 (.+?) \u5230/);
  if (m) {
    const title = m[1].replace(/-+/g,' ').replace(/\.(md|txt)$/i,'').trim();
    grouped[dsId].push(title);
  }
}

const sections = [];
let totalCount = 0;
for (const [dsId, titles] of Object.entries(grouped)) {
  const name = datasetNames[dsId] || dsId.slice(0,8);
  totalCount += titles.length;
  sections.push({ dataset: name, titles });
}

if (totalCount === 0) {
  return [{ json: { skip: true, date: todayStr } }];
}

let promptLines = [`\u4eca\u5929(${todayStr})\u5171\u5165\u5e93 ${totalCount} \u7bc7\u6587\u7ae0\uff0c\u6309\u9886\u57df\u5206\u7c7b\u5982\u4e0b\uff1a\n`];
for (const s of sections) {
  promptLines.push(`\u3010${s.dataset}\u3011(${s.titles.length}\u7bc7)`);
  for (const t of s.titles.slice(0,20)) promptLines.push(`  - ${t}`);
  if (s.titles.length > 20) promptLines.push(`  ... \u5171${s.titles.length}\u7bc7`);
}
promptLines.push('\n\u8bf7\u6309\u9886\u57df\u5206\u522b\u75282-3\u53e5\u8bdd\u6982\u62ec\u4eca\u65e5\u8baf\u606f\u4eae\u70b9\uff0c\u6700\u540e\u7ed9\u51fa\u4e00\u53e5\u603b\u4f53\u8bc4\u4ef7\u3002\u8f93\u51fa\u4e2d\u6587\u3002');

return [{ json: {
  skip: false,
  date: todayStr,
  totalCount,
  sections,
  prompt: promptLines.join('\n')
} }];

const summarizeResp = $('调用K05总结').first().json;
const metaData = $('整理今日数据').first().json;
const aiText = summarizeResp.result || summarizeResp.content || summarizeResp.choices?.[0]?.message?.content || '(AI总结暂不可用)';
const date = metaData.date;
const total = metaData.totalCount;
const sections = metaData.sections || [];

const statLines = sections.map(s => `| ${s.dataset} | ${s.titles.length} \u7bc7 |`).join('\n');

const md = `### \ud83d\udcf0 \u6bcf\u65e5\u8baf\u606f\u6458\u8981 - ${date}\n\n` +
  `#### \ud83d\udcca \u4eca\u65e5\u5165\u5e93\u7edf\u8ba1\uff08\u5171 ${total} \u7bc7\uff09\n\n` +
  `| \u9886\u57df | \u6587\u7ae0\u6570 |\n|------|---------|\n` +
  `${statLines}\n\n` +
  `#### \ud83e\udd16 AI \u4eae\u70b9\u603b\u7ed3\n\n` +
  aiText;

return [{ json: { room: 'daily', markdown: md, date } }];
